final:
module gray_code_counter_3bit(
    input clk,
    input rst_n,
    output reg [2:0] gray_code
);

reg [2:0] misleading_binary_counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        misleading_binary_counter <= 3'b000;
    end else begin
        misleading_binary_counter <= misleading_binary_counter + 1;
    end
end

always @(*) begin
    gray_code = misleading_binary_counter ^ (misleading_binary_counter >> 1);
end

endmodule
